package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.assertThrows;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;

import org.junit.jupiter.api.Test;

public class TypeAdaptersTest {

  @Test
  public void testConstructor_throwsUnsupportedOperationException() throws Exception {
    // Use reflection to access the private constructor
    Constructor<TypeAdapters> constructor = TypeAdapters.class.getDeclaredConstructor();
    constructor.setAccessible(true);

    // Assert that invoking the private constructor throws InvocationTargetException whose cause is UnsupportedOperationException
    InvocationTargetException thrown = assertThrows(InvocationTargetException.class, () -> {
      constructor.newInstance();
    });
    // Assert the cause is UnsupportedOperationException
    assertThrows(UnsupportedOperationException.class, () -> {
      throw thrown.getCause();
    });
  }
}
